CREATE TABLE IF NOT EXISTS users (
      id          TEXT PRIMARY KEY,
      name        TEXT NOT NULL,
      role        TEXT NOT NULL,
      roles       TEXT DEFAULT '[]',
      api_key     TEXT UNIQUE NOT NULL,
      stake       DOUBLE PRECISION DEFAULT 0,
      reputation  DOUBLE PRECISION DEFAULT 100,
      created_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , permanent_code TEXT, handle TEXT, region       TEXT DEFAULT 'global', search_anchor TEXT, email          TEXT, email_verified BIGINT DEFAULT 0, phone          TEXT, phone_verified BIGINT DEFAULT 0, password_hash  TEXT, failed_attempts BIGINT DEFAULT 0, locked_until   TEXT, sponsor_id   TEXT, sponsor_path TEXT, admin_type   TEXT, admin_scope  TEXT, admin_permissions TEXT, feed_visible BIGINT DEFAULT 1, bio TEXT, notify_claim_tasks BIGINT DEFAULT 1, shop_banner_url TEXT, shop_intro TEXT, handle_last_created_at TEXT, handle_change_log TEXT, geo_lat DOUBLE PRECISION, geo_lng DOUBLE PRECISION, geo_updated_at TEXT, default_address_text TEXT, default_address_region TEXT, default_address_json TEXT, placement_id    TEXT, placement_side  TEXT, placement_path  TEXT, placement_depth BIGINT DEFAULT 0, left_child_id   TEXT, right_child_id  TEXT, total_left_pv   DOUBLE PRECISION DEFAULT 0, total_right_pv  DOUBLE PRECISION DEFAULT 0, pv_dirty_at     TEXT, left_count      BIGINT DEFAULT 0, right_count     BIGINT DEFAULT 0, lifetime_score  DOUBLE PRECISION DEFAULT 0, mgmt_bonus_eligible BIGINT DEFAULT 0, l1_share_override BIGINT DEFAULT 0, placement_pref TEXT DEFAULT 'team_count', max_products      BIGINT DEFAULT 200, listing_paused    BIGINT DEFAULT 0, listing_paused_reason TEXT, listing_paused_by TEXT, listing_paused_at TEXT, webauthn_required_for_withdraw BIGINT DEFAULT 0, deleted_requested_at TEXT, deleted_at TEXT, rewards_opted_in BIGINT DEFAULT 0, store_accept_mode TEXT, store_shipping_template TEXT, store_shipping_quote_ok BIGINT, store_sale_regions TEXT, store_tax_lines TEXT, store_import_duty_terms TEXT, store_free_shipping_threshold DECIMAL(18,2));

CREATE TABLE IF NOT EXISTS products (
      id            TEXT PRIMARY KEY,
      seller_id     TEXT NOT NULL REFERENCES users(id),
      title         TEXT NOT NULL,
      description   TEXT NOT NULL,
      price         DOUBLE PRECISION NOT NULL,
      currency      TEXT DEFAULT 'WAZ',
      stock         BIGINT DEFAULT 1,
      category      TEXT,
      images        TEXT DEFAULT '[]',
      stake_amount  DOUBLE PRECISION DEFAULT 0,
      status        TEXT DEFAULT 'active',
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , specs TEXT, brand TEXT, model TEXT, source_price DOUBLE PRECISION, ship_regions TEXT DEFAULT '全国', handling_hours BIGINT DEFAULT 24, estimated_days TEXT, fragile BIGINT DEFAULT 0, return_days BIGINT DEFAULT 7, return_condition TEXT, warranty_days BIGINT DEFAULT 0, commission_rate DOUBLE PRECISION DEFAULT 0.10, total_likes BIGINT DEFAULT 0, has_variants BIGINT DEFAULT 0, claim_loss_count BIGINT DEFAULT 0, p2p_mode BIGINT DEFAULT 0, content_hash TEXT, peer_endpoint TEXT, content_signature TEXT, content_signed_at TEXT, category_id TEXT DEFAULT 'cat_default', listing_id TEXT, fulfillment_type TEXT DEFAULT 'standard', eta_hours DOUBLE PRECISION, freshness_ts TEXT, is_clearance BIGINT DEFAULT 0, clearance_until TEXT, cold_start_remaining BIGINT DEFAULT 30, listing_stake_locked DOUBLE PRECISION DEFAULT 0, source_url TEXT, source_price_at TEXT, weight_kg DOUBLE PRECISION, excluded_regions TEXT, commitment_hash TEXT, description_hash TEXT, price_hash TEXT, hashed_at TEXT, last_sold_at TEXT, completion_count BIGINT DEFAULT 0, dispute_loss_count BIGINT DEFAULT 0, unique_sharer_count BIGINT DEFAULT 0, metrics_backfilled_at TEXT, first_sold_at TEXT, product_type TEXT DEFAULT 'retail', stake_locked_at TEXT, origin_claims TEXT, i18n_titles TEXT, i18n_descs TEXT, value_badge BIGINT DEFAULT 0, value_badge_at TEXT, value_badge_rank BIGINT, value_badge_pct DOUBLE PRECISION, low_stock_threshold BIGINT DEFAULT 3, auto_delist_on_zero BIGINT DEFAULT 1, low_stock_alerted_at TEXT, auto_delisted_at TEXT, accept_mode TEXT, shipping_template TEXT, shipping_quote_ok BIGINT, package_size TEXT, origin_country TEXT, country_of_origin TEXT, customs_description TEXT, hs_code TEXT, sale_regions TEXT, tax_lines TEXT, import_duty_terms TEXT, free_shipping_threshold DECIMAL(18,2));

CREATE TABLE IF NOT EXISTS orders (
      id              TEXT PRIMARY KEY,
      product_id      TEXT NOT NULL REFERENCES products(id),
      buyer_id        TEXT NOT NULL REFERENCES users(id),
      seller_id       TEXT NOT NULL REFERENCES users(id),
      logistics_id    TEXT REFERENCES users(id),
      promoter_id     TEXT REFERENCES users(id),

      quantity        BIGINT DEFAULT 1,
      unit_price      DOUBLE PRECISION NOT NULL,
      total_amount    DOUBLE PRECISION NOT NULL,
      escrow_amount   DOUBLE PRECISION NOT NULL,


      status          TEXT NOT NULL DEFAULT 'created',














      pay_deadline      TEXT,
      accept_deadline   TEXT,
      ship_deadline     TEXT,
      pickup_deadline   TEXT,
      delivery_deadline TEXT,
      confirm_deadline  TEXT,

      shipping_address  TEXT,
      notes             TEXT,



      direct_pay_enabled_snapshot           BIGINT,
      direct_pay_rail_breaker_snapshot      BIGINT,
      direct_pay_region_snapshot            TEXT,
      direct_pay_region_allowlist_snapshot  TEXT,
      direct_pay_per_tx_cap_units_snapshot  BIGINT,
      direct_pay_seller_breaker_snapshot    BIGINT,
      direct_pay_decision_code              TEXT,
      created_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , payment_rail TEXT DEFAULT 'escrow', direct_pay_window_deadline TEXT, direct_grace_deadline TEXT, payment_query_deadline TEXT, payment_query_cancel_deadline TEXT, direct_pay_instruction_snapshot TEXT, direct_pay_account_snapshot TEXT, l1_uid TEXT, l2_uid TEXT, l3_uid TEXT, snapshot_commission_rate DOUBLE PRECISION, settled_commission_at TEXT, buyer_region TEXT, has_pending_claim BIGINT DEFAULT 0, source TEXT DEFAULT 'shop', fulfillment_mode TEXT DEFAULT 'shipping', settled_pv_at TEXT, settled_fault_at TEXT, bid_stake_held DOUBLE PRECISION DEFAULT 0, delivery_window TEXT, variant_id TEXT, variant_options_snapshot TEXT, gift_recipient_name TEXT, gift_recipient_phone TEXT, gift_message TEXT, insurance_premium DOUBLE PRECISION DEFAULT 0, stake_backing DOUBLE PRECISION DEFAULT 0, decline_reason_code TEXT, declined_at TEXT, decline_objective_pending BIGINT DEFAULT 0, decline_contest_deadline TEXT, decline_contested BIGINT DEFAULT 0, anonymous_recipient BIGINT DEFAULT 0, recipient_code TEXT, donation_amount DOUBLE PRECISION DEFAULT 0, coupon_id TEXT, coupon_discount DOUBLE PRECISION DEFAULT 0, content_hash_at_order TEXT, settled_pin_at TEXT, accept_mode_snapshot TEXT, pending_accept_deadline TEXT, ship_to_region TEXT, shipping_fee DECIMAL(18,2), shipping_est_days TEXT, shipping_quote_required BIGINT, shipping_quote_fee DECIMAL(18,2), shipping_quote_est_days TEXT, shipping_quote_note TEXT, shipping_quote_at TEXT, trade_terms_snapshot TEXT, delivery_failed_deadline TEXT, goods_return_deadline TEXT, return_shipping_actual DECIMAL(18,2));

CREATE TABLE IF NOT EXISTS order_state_history (
      id           TEXT PRIMARY KEY,
      order_id     TEXT NOT NULL REFERENCES orders(id),
      from_status  TEXT NOT NULL,
      to_status    TEXT NOT NULL,
      actor_id     TEXT NOT NULL REFERENCES users(id),
      actor_role   TEXT NOT NULL,
      evidence_ids TEXT DEFAULT '[]',
      notes        TEXT,
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS evidence (
      id           TEXT PRIMARY KEY,
      order_id     TEXT NOT NULL REFERENCES orders(id),
      uploader_id  TEXT NOT NULL REFERENCES users(id),
      type         TEXT NOT NULL,
      description  TEXT NOT NULL,
      file_path    TEXT,
      file_hash    TEXT,
      metadata     TEXT DEFAULT '{}',
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , size BIGINT DEFAULT 0, mime TEXT, sig TEXT, dispute_id TEXT, expires_at TEXT, withdrawn_at TEXT, filename TEXT, flag_reasons TEXT);

CREATE TABLE IF NOT EXISTS disputes (
      id              TEXT PRIMARY KEY,
      order_id        TEXT NOT NULL REFERENCES orders(id),
      initiator_id    TEXT NOT NULL REFERENCES users(id),
      reason          TEXT NOT NULL,
      stake_deposit   DOUBLE PRECISION DEFAULT 0,

      status          TEXT DEFAULT 'open',
      assigned_arbitrators TEXT DEFAULT '[]',
      verdict         TEXT,
      verdict_reason  TEXT,

      created_at      TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      resolved_at     TEXT
    , defendant_id TEXT, defendant_notes TEXT, defendant_evidence_ids TEXT DEFAULT '[]', respond_deadline TEXT, arbitrate_deadline TEXT, ruling_type TEXT, refund_amount DOUBLE PRECISION, party_evidence_ids TEXT DEFAULT '[]', liability_parties TEXT DEFAULT '[]', auto_judge_paused_until BIGINT, auto_judge_pause_reason TEXT, audit_log TEXT DEFAULT '[]', dispute_type TEXT DEFAULT 'buyer_dispute');

CREATE TABLE IF NOT EXISTS wallets (
      user_id   TEXT PRIMARY KEY REFERENCES users(id),
      balance   DOUBLE PRECISION DEFAULT 0,
      staked    DOUBLE PRECISION DEFAULT 0,
      escrowed  DOUBLE PRECISION DEFAULT 0,
      earned    DOUBLE PRECISION DEFAULT 0,
      updated_at TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , fee_staked DOUBLE PRECISION DEFAULT 0, deposit_address TEXT);

CREATE TABLE IF NOT EXISTS payouts (
      id           TEXT PRIMARY KEY,
      order_id     TEXT NOT NULL REFERENCES orders(id),
      recipient_id TEXT NOT NULL REFERENCES users(id),
      role         TEXT NOT NULL,
      amount       DOUBLE PRECISION NOT NULL,
      reason       TEXT NOT NULL,
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_receive_privileges (
      user_id          TEXT PRIMARY KEY REFERENCES users(id),
      status           TEXT NOT NULL DEFAULT 'none',
      tier             TEXT NOT NULL DEFAULT 'T0',
      suspended_reason TEXT,
      granted_at       TEXT,
      updated_at       TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_receive_deposits (
      id              TEXT PRIMARY KEY,
      user_id         TEXT NOT NULL REFERENCES users(id),
      tier            TEXT NOT NULL DEFAULT 'T0',
      required_amount DOUBLE PRECISION NOT NULL,
      amount          DOUBLE PRECISION NOT NULL DEFAULT 0,
      currency        TEXT NOT NULL CHECK (currency IN ('usdc','fiat')),
      deposit_rail    TEXT NOT NULL DEFAULT 'manual',
      external_ref    TEXT,
      status          TEXT NOT NULL DEFAULT 'pending',
      confirmed_at    TEXT,
      locked_at       TEXT,
      released_at     TEXT,
      production_receipt_confirmed_at TEXT,


      production_receipt_ref     TEXT,
      production_rail_id         TEXT,
      production_jurisdiction    TEXT,
      production_policy_version  TEXT,
      created_at      TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at      TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , reject_note TEXT, refund_requested_at TEXT, refund_evidence_ref TEXT, terms_version TEXT, platform_account_id TEXT);

CREATE TABLE IF NOT EXISTS direct_receive_payment_instructions (
      id           TEXT PRIMARY KEY,
      seller_id    TEXT NOT NULL REFERENCES users(id),
      instruction  TEXT NOT NULL,
      label        TEXT,
      status       TEXT NOT NULL DEFAULT 'active',
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_receive_accounts (
      id            TEXT PRIMARY KEY,
      seller_id     TEXT NOT NULL REFERENCES users(id),
      method        TEXT,
      currency      TEXT,
      instruction   TEXT NOT NULL,
      label         TEXT,
      qr_image_ref  TEXT,
      status        TEXT NOT NULL DEFAULT 'active',
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS platform_receive_accounts (
      id            TEXT PRIMARY KEY,
      label         TEXT,
      method        TEXT,
      currency      TEXT,
      instruction   TEXT NOT NULL,
      qr_data_uri   TEXT,
      status        TEXT NOT NULL DEFAULT 'active',
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_receive_account_qr_images (
      ref          TEXT NOT NULL,
      account_id   TEXT NOT NULL REFERENCES direct_receive_accounts(id),
      seller_id    TEXT NOT NULL REFERENCES users(id),
      mime         TEXT NOT NULL,
      data_b64     TEXT NOT NULL,
      byte_len     BIGINT NOT NULL,
      sha256       TEXT NOT NULL,
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      PRIMARY KEY (ref, seller_id)
    );

CREATE TABLE IF NOT EXISTS direct_receive_account_events (
      id           TEXT PRIMARY KEY,
      account_id   TEXT NOT NULL,
      seller_id    TEXT NOT NULL,
      event_type   TEXT NOT NULL,
      qr_ref       TEXT,
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_receive_deferrals (
      id                   TEXT PRIMARY KEY,
      user_id              TEXT NOT NULL REFERENCES users(id),
      reason               TEXT,
      period_days          BIGINT NOT NULL,
      reduced_quota_factor DOUBLE PRECISION NOT NULL DEFAULT 0.5,
      status               TEXT NOT NULL DEFAULT 'pending',
      approved_by          TEXT REFERENCES users(id),
      approved_at          TEXT,
      expires_at           TEXT,
      grace_until          TEXT,
      created_at           TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    , reminder_sent_at TEXT, satisfied_at TEXT);

CREATE TABLE IF NOT EXISTS product_verifications (
      id            TEXT PRIMARY KEY,
      product_id    TEXT NOT NULL REFERENCES products(id),
      seller_id     TEXT NOT NULL REFERENCES users(id),
      code          TEXT NOT NULL,
      platform      TEXT,
      external_url  TEXT,
      status        TEXT NOT NULL DEFAULT 'issued',
      reviewed_by   TEXT REFERENCES users(id),
      reviewed_at   TEXT,
      notes         TEXT,
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS store_verifications (
      id                 TEXT PRIMARY KEY,
      user_id            TEXT NOT NULL REFERENCES users(id),
      code               TEXT NOT NULL,
      platform           TEXT,
      external_url       TEXT,
      status             TEXT NOT NULL DEFAULT 'issued',
      per_product_exempt BIGINT NOT NULL DEFAULT 0,
      reviewed_by        TEXT REFERENCES users(id),
      reviewed_at        TEXT,
      notes              TEXT,
      created_at         TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at         TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_stakes (
      id          TEXT PRIMARY KEY,
      order_id    TEXT NOT NULL REFERENCES orders(id),
      seller_id   TEXT NOT NULL REFERENCES users(id),
      amount      DOUBLE PRECISION NOT NULL,
      status      TEXT NOT NULL DEFAULT 'locked',
      created_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      settled_at  TEXT,
      UNIQUE(order_id)
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_invoices (
      id            TEXT PRIMARY KEY,
      seller_id     TEXT NOT NULL REFERENCES users(id),
      period_start  TEXT NOT NULL,
      period_end    TEXT NOT NULL,
      total_amount  DOUBLE PRECISION NOT NULL CHECK (total_amount >= 0),
      currency      TEXT NOT NULL DEFAULT 'usdc' CHECK (currency = 'usdc'),
      due_date      TEXT NOT NULL,
      status        TEXT NOT NULL DEFAULT 'open' CHECK (status IN ('open','paid','overdue','void')),
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      created_by    TEXT,
      paid_at       TEXT
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_receivables (
      id          TEXT PRIMARY KEY,
      order_id    TEXT NOT NULL REFERENCES orders(id),
      seller_id   TEXT NOT NULL REFERENCES users(id),
      amount      DOUBLE PRECISION NOT NULL CHECK (amount >= 0),
      currency    TEXT NOT NULL DEFAULT 'usdc' CHECK (currency = 'usdc'),
      accrued_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      UNIQUE(order_id)
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_invoice_items (
      id            TEXT PRIMARY KEY,
      invoice_id    TEXT NOT NULL REFERENCES direct_pay_fee_invoices(id),
      receivable_id TEXT NOT NULL REFERENCES direct_pay_fee_receivables(id),
      amount        DOUBLE PRECISION NOT NULL CHECK (amount >= 0),
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      UNIQUE(receivable_id)
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_adjustments (
      id            TEXT PRIMARY KEY,
      receivable_id TEXT REFERENCES direct_pay_fee_receivables(id),
      seller_id     TEXT NOT NULL REFERENCES users(id),
      delta_amount  DOUBLE PRECISION NOT NULL,
      currency      TEXT NOT NULL DEFAULT 'usdc' CHECK (currency = 'usdc'),
      kind          TEXT NOT NULL CHECK (kind IN ('reversal','write_off','correction')),
      reason        TEXT,
      created_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      created_by    TEXT REFERENCES users(id)
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_invoice_events (
      id          TEXT PRIMARY KEY,
      invoice_id  TEXT NOT NULL REFERENCES direct_pay_fee_invoices(id),
      from_status TEXT,
      to_status   TEXT NOT NULL,
      actor       TEXT,
      reason      TEXT,
      created_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_payments (
      id          TEXT PRIMARY KEY,
      seller_id   TEXT NOT NULL REFERENCES users(id),
      invoice_id  TEXT REFERENCES direct_pay_fee_invoices(id),
      amount      DOUBLE PRECISION NOT NULL CHECK (amount >= 0),
      currency    TEXT NOT NULL DEFAULT 'usdc' CHECK (currency = 'usdc'),
      method      TEXT NOT NULL CHECK (method IN ('usdc','fiat')),
      received_at TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      recorded_by TEXT REFERENCES users(id),
      evidence_ref TEXT,
      note        TEXT
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_prepay_requests (
      id                   TEXT PRIMARY KEY,
      seller_id            TEXT NOT NULL REFERENCES users(id),
      amount_units         BIGINT NOT NULL,
      currency             TEXT,
      platform_account_id  TEXT NOT NULL REFERENCES platform_receive_accounts(id),
      evidence_ref         TEXT NOT NULL,
      evidence_note        TEXT,
      status               TEXT NOT NULL DEFAULT 'pending',
      created_at           TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      reviewed_by          TEXT REFERENCES users(id),
      reviewed_at          TEXT,
      review_note          TEXT,
      resulting_payment_id TEXT REFERENCES direct_pay_fee_payments(id)
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_ar_seller_overrides (
      seller_id     TEXT PRIMARY KEY REFERENCES users(id),
      ceiling_units BIGINT NOT NULL CHECK (ceiling_units >= 0),
      updated_by    TEXT REFERENCES users(id),
      updated_at    TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_ceiling_requests (
      id              TEXT PRIMARY KEY,
      seller_id       TEXT NOT NULL REFERENCES users(id),
      requested_units BIGINT NOT NULL CHECK (requested_units >= 0),
      effective_units_at_request BIGINT CHECK (effective_units_at_request >= 0),
      reason          TEXT,
      status          TEXT NOT NULL DEFAULT 'pending' CHECK (status IN ('pending','approved','rejected')),
      created_at      TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      reviewed_by     TEXT REFERENCES users(id),
      reviewed_at     TEXT,
      decision_note   TEXT
    );

CREATE TABLE IF NOT EXISTS direct_pay_fee_prepay_refunds (
      id           TEXT PRIMARY KEY,
      seller_id    TEXT NOT NULL REFERENCES users(id),
      amount       DOUBLE PRECISION NOT NULL CHECK (amount >= 0),
      currency     TEXT NOT NULL DEFAULT 'usdc' CHECK (currency = 'usdc'),
      method       TEXT NOT NULL CHECK (method IN ('usdc','fiat')),
      evidence_ref TEXT,
      reason       TEXT,
      recorded_by  TEXT REFERENCES users(id),
      created_at   TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS penalty_fund (
      id                    TEXT PRIMARY KEY,
      balance               DOUBLE PRECISION DEFAULT 0,
      total_fee_stake_slash DOUBLE PRECISION DEFAULT 0,
      total_base_bond_slash DOUBLE PRECISION DEFAULT 0,
      updated_at            TEXT
    );

CREATE TABLE IF NOT EXISTS penalty_fund_txns (
      id               TEXT PRIMARY KEY,
      kind             TEXT NOT NULL,
      source           TEXT NOT NULL,
      from_user_id     TEXT,
      amount           DOUBLE PRECISION NOT NULL,
      related_order_id TEXT,
      reason           TEXT,
      created_at       TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS sanctions_screening (
      id          TEXT PRIMARY KEY,
      user_id     TEXT NOT NULL REFERENCES users(id),
      status      TEXT NOT NULL DEFAULT 'clear',
      source      TEXT,
      reason      TEXT,
      screened_at TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      created_at  TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))

    , expires_at TEXT);

CREATE TABLE IF NOT EXISTS direct_receive_kyb_reviews (
