    created_at   TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
  );

CREATE TABLE IF NOT EXISTS build_task_quota_requests (
      id                       TEXT PRIMARY KEY,
      quota_type               TEXT NOT NULL DEFAULT 'build_task.create',
      requester_user_id        TEXT NOT NULL,
      requested_extra_count    BIGINT NOT NULL,
      reason                   TEXT NOT NULL,
      linked_refs              TEXT,
      urgency                  TEXT NOT NULL DEFAULT 'normal',
      requested_duration_hours BIGINT,
      requested_expires_at     TEXT,
      status                   TEXT NOT NULL DEFAULT 'pending',
      decided_at               TEXT,
      decided_by               TEXT,
      decision_note            TEXT,
      granted_count            BIGINT,
      consumed_count           BIGINT NOT NULL DEFAULT 0,
      expires_at               TEXT,
      created_at               TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      updated_at               TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS build_task_quota_events (
      id          TEXT PRIMARY KEY,
      request_id  TEXT NOT NULL,
      actor_id    TEXT,
      action      TEXT NOT NULL,
      detail      TEXT,
      created_at  TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS build_reputation (
