      build_points BIGINT NOT NULL DEFAULT 0,
      updated_at   TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS build_reputation_events (
      id         TEXT PRIMARY KEY,
      user_id    TEXT NOT NULL,
      source     TEXT NOT NULL,
      points     BIGINT NOT NULL,
      ref_id     TEXT,
      note       TEXT,
      created_at TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
    );

CREATE TABLE IF NOT EXISTS github_contribution_credentials (
    credential_id        TEXT PRIMARY KEY,
    core_digest          TEXT NOT NULL UNIQUE,
    credential_version   TEXT NOT NULL,
    source_event_key     TEXT NOT NULL,
    repository_id        TEXT NOT NULL,
    pr_node_id           TEXT NOT NULL,
    pr_number            BIGINT NOT NULL,
    merge_commit_sha     TEXT NOT NULL,
    merged_at            TEXT NOT NULL,
    github_actor_id      TEXT NOT NULL,
    lifecycle_event      TEXT NOT NULL CHECK (lifecycle_event = 'merged'),
    core_json            TEXT NOT NULL,
    created_at           TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
    UNIQUE (credential_id, source_event_key)
  );

CREATE TABLE IF NOT EXISTS github_credential_observations (
    id                   TEXT PRIMARY KEY,
    credential_id        TEXT NOT NULL REFERENCES github_contribution_credentials(credential_id),
    observation_digest   TEXT NOT NULL,
    observation_json     TEXT NOT NULL,
    observed_at          TEXT NOT NULL,
    created_at           TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
    UNIQUE (credential_id, observation_digest)
  );

CREATE TABLE IF NOT EXISTS contribution_facts (
    fact_id              TEXT PRIMARY KEY,
    source_event_key     TEXT NOT NULL UNIQUE,
    source               TEXT NOT NULL CHECK (source IN ('github','in_protocol','governance','transaction')),
    type                 TEXT CHECK (type IS NULL OR type IN ('code','tests','audit','maintenance','governance','usage','transaction','referral')),
    artifact_ref         TEXT NOT NULL,
    occurred_at          TEXT,
    executor_ref         TEXT NOT NULL,
    accountable_ref      TEXT,
    provenance           TEXT NOT NULL DEFAULT 'unknown' CHECK (provenance IN ('human','ai_assisted','ai_authored','unknown')),
    status               TEXT NOT NULL CHECK (status IN ('active','superseded','reverted','void','forfeited')),
    immutable            BIGINT NOT NULL DEFAULT 1 CHECK (immutable = 1),
    created_at           TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
    UNIQUE (fact_id, source_event_key)
  );

CREATE TABLE IF NOT EXISTS github_fact_credentials (
    fact_id              TEXT NOT NULL,
    credential_id        TEXT NOT NULL,
    source_event_key     TEXT NOT NULL,
    created_at           TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
    PRIMARY KEY (fact_id, credential_id),
    UNIQUE (credential_id),
    FOREIGN KEY (credential_id, source_event_key) REFERENCES github_contribution_credentials(credential_id, source_event_key),
    FOREIGN KEY (fact_id, source_event_key) REFERENCES contribution_facts(fact_id, source_event_key)
  );

CREATE TABLE IF NOT EXISTS identity_binding_events (
    event_id             TEXT PRIMARY KEY,
    event_type           TEXT NOT NULL CHECK (event_type IN ('bound','revoked')),
    github_actor_id      TEXT NOT NULL,
    account_id           TEXT NOT NULL REFERENCES users(id),
    visibility           TEXT NOT NULL DEFAULT 'private' CHECK (visibility IN ('private','public')),
    proof_method         TEXT NOT NULL CHECK (proof_method IN ('github_publication_challenge','admin_manual')),
    proof_ref            TEXT,
    supersedes_event_id  TEXT REFERENCES identity_binding_events(event_id),
    created_at           TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
    immutable            BIGINT NOT NULL DEFAULT 1 CHECK (immutable = 1),
    UNIQUE (event_id, event_type, github_actor_id, account_id, visibility)
  );

CREATE TABLE IF NOT EXISTS identity_bindings_active (
    github_actor_id      TEXT PRIMARY KEY,
    account_id           TEXT NOT NULL REFERENCES users(id),
    visibility           TEXT NOT NULL DEFAULT 'private' CHECK (visibility IN ('private','public')),
    bound_event_id       TEXT NOT NULL,
    ref_event_type       TEXT NOT NULL DEFAULT 'bound' CHECK (ref_event_type = 'bound'),
    bound_at             TEXT NOT NULL,
    FOREIGN KEY (bound_event_id, ref_event_type, github_actor_id, account_id, visibility)
      REFERENCES identity_binding_events(event_id, event_type, github_actor_id, account_id, visibility)
  );

CREATE TABLE IF NOT EXISTS identity_claim_challenges (
      challenge_id         TEXT PRIMARY KEY,
      account_id           TEXT NOT NULL REFERENCES users(id),
      github_actor_id      TEXT NOT NULL,
      source_event_key     TEXT NOT NULL,
      nonce_hash           TEXT NOT NULL UNIQUE CHECK (length(nonce_hash) = 64 AND nonce_hash !~ '[^0-9a-f]'),
      status               TEXT NOT NULL CHECK (status IN ('issued','consumed','expired','revoked')),
      expires_at           TEXT NOT NULL,
      consumed_at          TEXT,
      created_at           TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
      immutable            BIGINT NOT NULL DEFAULT 1 CHECK (immutable = 1),
      CHECK ((status = 'consumed' AND consumed_at IS NOT NULL) OR (status <> 'consumed' AND consumed_at IS NULL))
    );

CREATE TABLE IF NOT EXISTS snf_messages (
