    current_price         DOUBLE PRECISION NOT NULL,
    min_increment         DOUBLE PRECISION NOT NULL DEFAULT 1,
    reserve_price         DOUBLE PRECISION,
    buyer_stake_pct       DOUBLE PRECISION DEFAULT 0.05,
    deadline_at           TEXT NOT NULL,
    sniper_extend_min     BIGINT NOT NULL DEFAULT 5,
    seller_stake_locked   DOUBLE PRECISION NOT NULL DEFAULT 0,
    status                TEXT NOT NULL DEFAULT 'open',
    winning_bid_id        TEXT,
    bid_count             BIGINT NOT NULL DEFAULT 0,
    awarded_at            TEXT,
    notes                 TEXT,
    created_at            TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')),
    updated_at            TEXT DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS'))
  , max_extends BIGINT DEFAULT 10, extends_used BIGINT DEFAULT 0, claim_loss_count BIGINT DEFAULT 0);

CREATE TABLE IF NOT EXISTS auction_bids (
    id                TEXT PRIMARY KEY,
    auction_id        TEXT NOT NULL,
    buyer_id          TEXT NOT NULL,
    price             DOUBLE PRECISION NOT NULL,
    stake_locked      DOUBLE PRECISION NOT NULL DEFAULT 0,
