  created_at TEXT NOT NULL DEFAULT (to_char((now() AT TIME ZONE 'UTC'), 'YYYY-MM-DD HH24:MI:SS')), expires_at TEXT NOT NULL, approved_at TEXT , kind TEXT, order_id TEXT, order_action TEXT, params_hash TEXT, action_params TEXT, executed_at TEXT, execution_result TEXT);

