-- ════════════ APPEND-ONLY GUARDS (immutability triggers) ════════════
CREATE OR REPLACE FUNCTION webaz_reject_mutation() RETURNS trigger AS $$
BEGIN RAISE EXCEPTION 'table % is append-only (UPDATE/DELETE forbidden)', TG_TABLE_NAME; END;
$$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_identity_binding_events_no_update ON identity_binding_events;
CREATE TRIGGER trg_identity_binding_events_no_update BEFORE UPDATE ON identity_binding_events FOR EACH ROW EXECUTE FUNCTION webaz_reject_mutation();
DROP TRIGGER IF EXISTS trg_identity_binding_events_no_delete ON identity_binding_events;
CREATE TRIGGER trg_identity_binding_events_no_delete BEFORE DELETE ON identity_binding_events FOR EACH ROW EXECUTE FUNCTION webaz_reject_mutation();
