-- ════════════ INSERT-STATUS GUARDS ════════════
CREATE OR REPLACE FUNCTION webaz_identity_claim_challenges_insert_issued() RETURNS trigger AS $$
BEGIN IF NEW.status <> 'issued' THEN RAISE EXCEPTION 'identity_claim_challenges must be inserted with status=issued'; END IF; RETURN NEW; END;
$$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_identity_claim_challenges_insert_issued ON identity_claim_challenges;
CREATE TRIGGER trg_identity_claim_challenges_insert_issued BEFORE INSERT ON identity_claim_challenges FOR EACH ROW EXECUTE FUNCTION webaz_identity_claim_challenges_insert_issued();

-- ════════════ REFERENCED-EVIDENCE FREEZE (admin_audit_log) ════════════
CREATE OR REPLACE FUNCTION webaz_aal_freeze_evidence() RETURNS trigger AS $$
BEGIN IF EXISTS (SELECT 1 FROM admin_coordination_fact_sources WHERE admin_audit_log_id = OLD.id) THEN RAISE EXCEPTION 'admin_audit_log row is referenced as contribution evidence — immutable'; END IF; RETURN OLD; END;
$$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_aal_freeze_evidence_update ON admin_audit_log;
CREATE TRIGGER trg_aal_freeze_evidence_update BEFORE UPDATE ON admin_audit_log FOR EACH ROW EXECUTE FUNCTION webaz_aal_freeze_evidence();
DROP TRIGGER IF EXISTS trg_aal_freeze_evidence_delete ON admin_audit_log;
CREATE TRIGGER trg_aal_freeze_evidence_delete BEFORE DELETE ON admin_audit_log FOR EACH ROW EXECUTE FUNCTION webaz_aal_freeze_evidence();

-- ════════════ CONFIRMATION-MATCH GUARD (admin_operator_claim_confirmations) ════════════
CREATE OR REPLACE FUNCTION webaz_aocc_match_claim() RETURNS trigger AS $$
BEGIN IF NOT EXISTS (SELECT 1 FROM admin_operator_claim_events e WHERE e.event_id = NEW.claimed_event_id AND e.event_type = 'claimed' AND e.admin_account_id = NEW.admin_account_id AND e.contributor_account_id = NEW.contributor_account_id) THEN RAISE EXCEPTION 'confirmation admin/contributor must match its claimed event'; END IF; RETURN NEW; END;
$$ LANGUAGE plpgsql;
DROP TRIGGER IF EXISTS trg_aocc_match_claim ON admin_operator_claim_confirmations;
CREATE TRIGGER trg_aocc_match_claim BEFORE INSERT ON admin_operator_claim_confirmations FOR EACH ROW EXECUTE FUNCTION webaz_aocc_match_claim();

COMMIT;
